                    let root_id = match input["entity_id"].as_u64() {
                        Some(id) => id,
                        None => return McpToolOutput::error("missing entity_id"),
                    };
                    let s = snap_deldesc.lock().unwrap();
                    let mut children: std::collections::HashMap<u64, Vec<u64>> =
                        std::collections::HashMap::new();
