            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let result = mcp
                .0
                .lock()
                .unwrap()
                .execute(
                    "attach_mesh",
                    json!({"entity_id": eid.index() as u64, "mesh_id": 42u64}),
                )
                .expect("attach_mesh not found");
            assert!(result.is_ok(), "{:?}", result.error);
