    #[test]
    fn mcp_count_and_deselect_entities_with_light() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        // Spawn 2 point lights and 1 plain entity
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "spawn_point_light",
                    json!({
                        "color": [1.0, 1.0, 1.0], "intensity": 100.0, "range": 10.0,
                        "position": [0.0, 0.0, 0.0]
                    }),
                )
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "spawn_point_light",
                    json!({
                        "color": [1.0, 0.0, 0.0], "intensity": 200.0, "range": 5.0,
                        "position": [1.0, 0.0, 0.0]
                    }),
                )
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Plain"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();

        // count_entities_with_light → 2
        let count_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_with_light", json!({}))
            .unwrap();
        assert!(count_out.is_ok());
        assert_eq!(count_out.content["count"], 2, "2 light entities");

        // select all, deselect_entities_with_light → 2 removed
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_all", json!({}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute("deselect_entities_with_light", json!({}))
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["removed_count"], 2);
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let plain_sel = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Plain"))
                .unwrap()["selected"]
                .as_bool()
                .unwrap();
            let light_still_sel: Vec<bool> = entities
                .iter()
                .filter(|e| e["light_type"].is_string())
                .map(|e| e["selected"].as_bool().unwrap())
                .collect();
            assert!(plain_sel, "Plain still selected");
            assert!(light_still_sel.iter().all(|&s| !s), "all lights deselected");
        }
    }

    #[test]
    fn mcp_count_entities_by_name_starts_and_ends_with() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Enemy_A"}, {"name": "Enemy_B"}, {"name": "Player"},
                        {"name": "Wall_Left"}, {"name": "Wall_Right"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();

        // count_entities_by_name_starts_with("Enemy") → 2
        let count_start = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "count_entities_by_name_starts_with",
                json!({"prefix": "Enemy"}),
            )
            .unwrap();
        assert!(count_start.is_ok());
        assert_eq!(count_start.content["count"], 2);

        // count_entities_by_name_starts_with("Wall") → 2
        let count_wall = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "count_entities_by_name_starts_with",
                json!({"prefix": "Wall"}),
            )
            .unwrap();
        assert_eq!(count_wall.content["count"], 2);

        // count_entities_by_name_starts_with("NPC") → 0
        let count_npc = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "count_entities_by_name_starts_with",
                json!({"prefix": "NPC"}),
            )
            .unwrap();
        assert_eq!(count_npc.content["count"], 0);

        // count_entities_by_name_ends_with("_B") → 1 (Enemy_B)
        let count_b = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_by_name_ends_with", json!({"suffix": "_B"}))
            .unwrap();
        assert!(count_b.is_ok());
        assert_eq!(count_b.content["count"], 1);

        // count_entities_by_name_ends_with("_A") → 1 (Enemy_A)
        let count_a = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_by_name_ends_with", json!({"suffix": "_A"}))
            .unwrap();
        assert_eq!(count_a.content["count"], 1);
    }

