    #[test]
    fn mcp_get_and_count_entities_by_visibility() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Visible1"}, {"name": "Visible2"}, {"name": "Hidden"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_hidden = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Hidden"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("hide_entity", json!({"entity_id": id_hidden}))
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();

        let visible_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_by_visibility", json!({"visible": true}))
            .unwrap();
        assert!(visible_out.is_ok());
        let visible_ids: Vec<u64> = visible_out.content["entities"]
            .as_array()
            .unwrap()
            .iter()
            .map(|e| e["id"].as_u64().unwrap())
            .collect();
        assert_eq!(visible_ids.len(), 2, "two visible entities");

        let hidden_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_by_visibility", json!({"visible": false}))
            .unwrap();
        assert!(hidden_out.is_ok());
        let hidden_ids: Vec<u64> = hidden_out.content["entities"]
            .as_array()
            .unwrap()
            .iter()
            .map(|e| e["id"].as_u64().unwrap())
            .collect();
        assert_eq!(hidden_ids.len(), 1, "one hidden entity");

        let count_vis = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_by_visibility", json!({"visible": true}))
            .unwrap();
        assert!(count_vis.is_ok());
        assert_eq!(count_vis.content["count"], 2);

        let count_hid = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_by_visibility", json!({"visible": false}))
            .unwrap();
        assert!(count_hid.is_ok());
        assert_eq!(count_hid.content["count"], 1);
    }

    #[test]
    fn mcp_select_and_count_entities_with_any_of_tags() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Alpha"}, {"name": "Beta"}, {"name": "Both"}, {"name": "Neither"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_alpha = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Alpha"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_both = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Both"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_alpha, "tag": "alpha"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_both, "tag": "alpha"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_beta = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Beta"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_both = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("Both"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_beta, "tag": "beta"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_both, "tag": "beta"}))
                .unwrap();
        }
        app.update();
        app.update();

        // count_entities_with_any_of_tags([alpha, beta]): Alpha, Beta, Both = 3
        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let count_out = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "count_entities_with_any_of_tags",
                json!({"tags": ["alpha", "beta"]}),
            )
            .unwrap();
        assert!(count_out.is_ok());
        assert_eq!(
            count_out.content["count"], 3,
            "Alpha, Beta, Both match any of [alpha,beta]"
        );

        // select_entities_with_any_of_tags([alpha]): Alpha, Both selected
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "select_entities_with_any_of_tags",
                    json!({"tags": ["alpha"]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let entities = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let alpha_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("Alpha"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        let beta_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("Beta"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        let both_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("Both"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        let neither_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("Neither"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        assert!(alpha_sel, "Alpha selected");
        assert!(!beta_sel, "Beta not selected");
        assert!(both_sel, "Both selected");
        assert!(!neither_sel, "Neither not selected");
    }

