    #[test]
    fn mcp_get_tags_shared_by_selection_and_entities_sharing_all_tags() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "A"}, {"name": "B"}, {"name": "C"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // A: [shared, only_a], B: [shared, only_b], C: [shared, only_c]
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_a = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("A"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_b = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_c = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("C"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_a, "tag": "shared"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_b, "tag": "shared"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_c, "tag": "shared"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_a = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("A"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_b = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_a, "tag": "only_a"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_b, "tag": "only_b"}))
                .unwrap();
        }
        app.update();
        app.update();

        // select A and B
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "select_entities_with_tag_containing",
                    json!({"substring": "shared"}),
                )
                .unwrap();
        }
        app.update();
        app.update();
        // deselect C
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "deselect_entities_with_tag_containing",
                    json!({"substring": "only_"}),
                )
                .unwrap();
        }
        // C has no "only_" tag so stays selected — select only A and B via AABB is simpler, but just select all and deselect C via tag
        // Actually let's just select A and B directly: select all tagged "only_a" or "only_b", then select "shared" + those
        // Simpler: use select_entities_within_aabb if we place them, but they have no position.
        // Instead: deselect_all then select A and B by name
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("deselect_all", json!({}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "select_entities_with_name_containing",
                    json!({"substring": "A"}),
                )
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "select_entities_with_name_containing",
                    json!({"substring": "B"}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // get_tags_shared_by_selection: A and B both have "shared"; A has "only_a", B has "only_b" → only "shared" is common
        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let shared_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_tags_shared_by_selection", json!({}))
            .unwrap();
        assert!(shared_out.is_ok());
        let tags = shared_out.content["tags"].as_array().unwrap();
        assert_eq!(tags.len(), 1);
        assert_eq!(tags[0].as_str(), Some("shared"));

        // get_entities_sharing_all_tags(["shared"]): A, B, C all have it → 3
        let all_tags_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_sharing_all_tags", json!({"tags": ["shared"]}))
            .unwrap();
        assert!(all_tags_out.is_ok());
        let entities = all_tags_out.content["entities"].as_array().unwrap();
        assert_eq!(entities.len(), 3);
    }

    #[test]
    fn mcp_count_all_tags_and_get_tag_frequency() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "A"}, {"name": "B"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // A: [alpha], B: [alpha, beta] → total tags = 3, alpha=2, beta=1
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_a = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("A"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_b = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_a, "tag": "alpha"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_b, "tag": "alpha"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_b = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_b, "tag": "beta"}))
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let count_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_all_tags", json!({}))
            .unwrap();
        assert!(count_out.is_ok());
        assert_eq!(
            count_out.content["count"], 3,
            "total tag assignments: A=1, B=2"
        );

        let freq_out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_tag_frequency", json!({}))
            .unwrap();
        assert!(freq_out.is_ok());
        let freqs = freq_out.content["frequencies"].as_array().unwrap();
        let alpha_count = freqs
            .iter()
            .find(|f| f["tag"].as_str() == Some("alpha"))
            .unwrap()["count"]
            .as_u64()
            .unwrap();
        let beta_count = freqs
            .iter()
            .find(|f| f["tag"].as_str() == Some("beta"))
            .unwrap()["count"]
            .as_u64()
            .unwrap();
        assert_eq!(alpha_count, 2);
        assert_eq!(beta_count, 1);
    }

