    #[test]
    fn mcp_select_and_deselect_entities_with_tag_containing() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "A"}, {"name": "B"}, {"name": "C"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // tag A and B with "team:*", C with "solo"
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let id_a = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("A"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_b = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let id_c = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("C"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "tag_entity",
                    json!({"entity_id": id_a, "tag": "team:alpha"}),
                )
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_b, "tag": "team:beta"}))
                .unwrap();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": id_c, "tag": "solo"}))
                .unwrap();
        }
        app.update();
        app.update();

        // select entities with tag containing "team:"
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "select_entities_with_tag_containing",
                    json!({"substring": "team:"}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let entities = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let a_sel = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("A"))
                .unwrap()["selected"]
                .as_bool()
                .unwrap();
            let b_sel = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("B"))
                .unwrap()["selected"]
                .as_bool()
                .unwrap();
            let c_sel = entities
                .iter()
                .find(|e| e["name"].as_str() == Some("C"))
                .unwrap()["selected"]
                .as_bool()
                .unwrap();
            assert!(a_sel, "A selected");
            assert!(b_sel, "B selected");
            assert!(!c_sel, "C not selected");
        }

        // deselect entities with tag containing "team:"
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "deselect_entities_with_tag_containing",
                    json!({"substring": "team:"}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let entities = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let a_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("A"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        let b_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("B"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        assert!(!a_sel, "A deselected");
        assert!(!b_sel, "B deselected");
    }

