    #[test]
    fn mcp_deselect_entities_within_aabb_clears_inside() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "In",  "position": [3.0, 3.0, 3.0]},
                        {"name": "Out", "position": [50.0, 50.0, 50.0]},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // select both
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_all", json!({}))
                .unwrap();
        }
        app.update();
        app.update();

        // deselect only "In"
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "deselect_entities_within_aabb",
                    json!({
                        "min_x": 0.0, "min_y": 0.0, "min_z": 0.0,
                        "max_x": 10.0, "max_y": 10.0, "max_z": 10.0,
                    }),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let entities = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let in_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("In"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        let out_sel = entities
            .iter()
            .find(|e| e["name"].as_str() == Some("Out"))
            .unwrap()["selected"]
            .as_bool()
            .unwrap();
        assert!(!in_sel, "In deselected");
        assert!(out_sel, "Out still selected");
    }

