    #[test]
    fn mcp_get_tags_used_by_selection_returns_tags_of_selected() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "SelA"},
                        {"name": "SelB"},
                        {"name": "NotSel"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let a_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("SelA"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();
        let b_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("SelB"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();
        let ns_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("NotSel"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": a_id, "tag": "hero"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": b_id, "tag": "villain"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": ns_id, "tag": "npc"}))
                .unwrap();
        }
        app.update();
        app.update();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let mut reg = mcp.0.lock().unwrap();
            reg.execute("select_entity", json!({"entity_id": a_id}))
                .unwrap();
            reg.execute("select_entity", json!({"entity_id": b_id}))
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let mut reg = mcp.0.lock().unwrap();

        let out = reg
            .execute("get_tags_used_by_selection", json!({}))
            .unwrap();
        assert!(out.is_ok());
        let tags: Vec<String> = out.content["tags"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_str().unwrap().to_string())
            .collect();
        assert!(tags.contains(&"hero".to_string()));
        assert!(tags.contains(&"villain".to_string()));
        assert!(!tags.contains(&"npc".to_string()), "npc not in selection");

        let out2 = reg
            .execute("count_tags_used_by_selection", json!({}))
            .unwrap();
        assert!(out2.is_ok());
        assert_eq!(out2.content["count"], 2);
    }

    #[test]
    fn mcp_count_entities_with_no_children_returns_correct_count() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Root"},
                        {"name": "Child"},
                        {"name": "Leaf"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let root_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("Root"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();
        let child_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("Child"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();
        let leaf_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("Leaf"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let mut reg = mcp.0.lock().unwrap();
            reg.execute(
                "set_parent",
                json!({"entity_id": child_id, "parent_id": root_id}),
            )
            .unwrap();
            reg.execute(
                "set_parent",
                json!({"entity_id": leaf_id, "parent_id": child_id}),
            )
            .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_with_no_children", json!({}))
            .unwrap();
        assert!(out.is_ok());
        // Root has Child; Child has Leaf; Leaf has no children
        assert_eq!(out.content["count"], 1, "only Leaf has no children");
    }

