    fn mcp_count_entities_without_parent_returns_correct_count() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Parent"},
                        {"name": "Child"},
                        {"name": "Orphan"},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let parent_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("Parent"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();
        let child_id = all
            .iter()
            .find(|e| e["name"].as_str() == Some("Child"))
            .unwrap()["id"]
            .as_u64()
            .unwrap();

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_parent",
                    json!({"entity_id": child_id, "parent_id": parent_id}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("count_entities_without_parent", json!({}))
            .unwrap();
        assert!(out.is_ok());
        assert_eq!(out.content["count"], 2, "Parent and Orphan have no parent");
    }

