        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_by_name_prefix", json!({"prefix": "Enemy"}))
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["entity_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap())
            .collect();
        assert!(ids.contains(&ea_id));
