    #[test]
    fn mcp_get_entities_with_positive_z_returns_entities_with_z_greater_than_zero() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "PosZ", "position": [0.0, 0.0,  7.0]},
                        {"name": "Zero", "position": [0.0, 0.0,  0.0]},
                        {"name": "NegZ", "position": [0.0, 0.0, -5.0]},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (pos_id, zero_id, neg_id) = (id_of("PosZ"), id_of("Zero"), id_of("NegZ"));

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_with_positive_z", json!({}))
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["entity_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap())
            .collect();
        assert!(ids.contains(&pos_id), "PosZ included (z=7)");
        assert!(!ids.contains(&zero_id), "Zero excluded (z=0)");
        assert!(!ids.contains(&neg_id), "NegZ excluded (z=-5)");
    }

