    #[test]
    fn mcp_get_light_type_of_entity_returns_correct_type() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_point_light", json!({"color": [1.0, 1.0, 1.0], "intensity": 100.0, "range": 5.0, "position": [0.0, 0.0, 0.0]})).unwrap();
            m.execute(
                "batch_spawn",
                json!({"entities": [{"name": "NoLight", "position": [1.0, 0.0, 0.0]}]}),
            )
            .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let point_ent = all
            .iter()
            .find(|e| e["light_type"].as_str() == Some("point"))
            .unwrap();
        let plain_ent = all
            .iter()
            .find(|e| e["name"].as_str() == Some("NoLight"))
            .unwrap();
        let (point_id, plain_id) = (
            point_ent["id"].as_u64().unwrap(),
            plain_ent["id"].as_u64().unwrap(),
        );

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute("get_light_type_of_entity", json!({"entity_id": point_id}))
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["light_type"].as_str().unwrap(), "point");
        }

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_light_type_of_entity", json!({"entity_id": plain_id}))
            .unwrap();
        assert!(out.is_ok());
        assert!(
            out.content["light_type"].is_null(),
            "no light_type for plain entity"
        );
    }

    #[test]
    fn mcp_get_entities_with_light_range_between_filters_correctly() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_point_light", json!({"color": [1.0, 1.0, 1.0], "intensity": 100.0, "range": 3.0, "position": [0.0, 0.0, 0.0]})).unwrap();
            m.execute("spawn_point_light", json!({"color": [1.0, 1.0, 1.0], "intensity": 100.0, "range": 7.0, "position": [1.0, 0.0, 0.0]})).unwrap();
            m.execute("spawn_point_light", json!({"color": [1.0, 1.0, 1.0], "intensity": 100.0, "range": 15.0, "position": [2.0, 0.0, 0.0]})).unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_with_range = |r: f64| -> u64 {
            all.iter()
                .find(|e| {
                    e["light_range"]
                        .as_f64()
                        .map(|v| (v - r).abs() < 0.1)
                        .unwrap_or(false)
                })
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (id3, id7, id15) = (id_with_range(3.0), id_with_range(7.0), id_with_range(15.0));

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "get_entities_with_light_range_between",
                json!({"min": 5.0, "max": 10.0}),
            )
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["entity_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap())
            .collect();
        assert!(!ids.contains(&id3), "range 3 excluded (< min)");
        assert!(ids.contains(&id7), "range 7 included");
        assert!(!ids.contains(&id15), "range 15 excluded (> max)");
    }

    #[test]
    fn mcp_get_entity_ancestor_ids_returns_chain_to_root() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "GrandParent", "position": [0.0, 0.0, 0.0]},
                        {"name": "Parent",      "position": [1.0, 0.0, 0.0]},
                        {"name": "Leaf",        "position": [2.0, 0.0, 0.0]},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (gp_id, parent_id, leaf_id) = (id_of("GrandParent"), id_of("Parent"), id_of("Leaf"));

        // Chain: Leaf → Parent → GrandParent
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute(
                "set_parent",
                json!({"entity_id": parent_id, "parent_id": gp_id}),
            )
            .unwrap();
            m.execute(
                "set_parent",
                json!({"entity_id": leaf_id, "parent_id": parent_id}),
            )
            .unwrap();
        }
        app.update();
        app.update();

        // Root has no ancestors
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute("get_entity_ancestor_ids", json!({"entity_id": gp_id}))
                .unwrap();
            assert!(out.is_ok());
            let ids: Vec<u64> = out.content["ancestor_ids"]
                .as_array()
                .unwrap()
                .iter()
                .map(|v| v.as_u64().unwrap())
                .collect();
            assert!(ids.is_empty(), "root has no ancestors");
        }

        // Leaf has Parent and GrandParent as ancestors
        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entity_ancestor_ids", json!({"entity_id": leaf_id}))
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["ancestor_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap())
            .collect();
        assert!(ids.contains(&parent_id), "parent in ancestors");
        assert!(ids.contains(&gp_id), "grandparent in ancestors");
        assert!(!ids.contains(&leaf_id), "self not in ancestors");
    }

    #[test]
    fn mcp_get_entity_sibling_ids_returns_same_parent_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "Parent", "position": [0.0, 0.0, 0.0]},
                        {"name": "ChildA", "position": [1.0, 0.0, 0.0]},
                        {"name": "ChildB", "position": [2.0, 0.0, 0.0]},
                        {"name": "ChildC", "position": [3.0, 0.0, 0.0]},
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (parent_id, a_id, b_id, c_id) = (
            id_of("Parent"),
            id_of("ChildA"),
            id_of("ChildB"),
            id_of("ChildC"),
        );

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute(
                "set_parent",
                json!({"entity_id": a_id, "parent_id": parent_id}),
            )
            .unwrap();
            m.execute(
                "set_parent",
                json!({"entity_id": b_id, "parent_id": parent_id}),
            )
            .unwrap();
            m.execute(
                "set_parent",
                json!({"entity_id": c_id, "parent_id": parent_id}),
            )
            .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entity_sibling_ids", json!({"entity_id": a_id}))
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["sibling_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_u64().unwrap())
            .collect();
        assert!(ids.contains(&b_id), "ChildB is sibling of ChildA");
        assert!(ids.contains(&c_id), "ChildC is sibling of ChildA");
        assert!(!ids.contains(&a_id), "self not in siblings");
        assert!(!ids.contains(&parent_id), "parent not in siblings");
    }

