    #[test]
    fn mcp_get_entities_with_more_than_n_tags_filters_strictly_above_n() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "A"})).unwrap();
            m.execute("spawn_entity", json!({"name": "B"})).unwrap();
            m.execute("spawn_entity", json!({"name": "C"})).unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (a_id, b_id, c_id) = (id_of("A"), id_of("B"), id_of("C"));

        // A: 3 tags, B: 2 tags, C: 1 tag
        for (id, tags) in [
            (a_id, vec!["x", "y", "z"]),
            (b_id, vec!["x", "y"]),
            (c_id, vec!["x"]),
        ] {
            for tag in tags {
                let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
                mcp.0
                    .lock()
                    .unwrap()
                    .execute("tag_entity", json!({"entity_id": id, "tag": tag}))
                    .unwrap();
                drop(mcp);
                app.update();
                app.update();
            }
        }

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_with_more_than_n_tags", json!({"n": 2}))
            .unwrap();
        assert!(out.is_ok());
        let ents = out.content["entities"].as_array().unwrap();
        let ids: Vec<u64> = ents.iter().map(|e| e["id"].as_u64().unwrap()).collect();
        assert!(ids.contains(&a_id), "A (3 tags) > 2 included");
        assert!(!ids.contains(&b_id), "B (2 tags) == 2 excluded");
        assert!(!ids.contains(&c_id), "C (1 tag) < 2 excluded");
    }

    #[test]
    fn mcp_get_entities_with_exactly_one_child_returns_single_child_parents() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "OneChild"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "TwoChildren"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "NoChild"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "Child1"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "Child2a"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "Child2b"}))
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (one_id, two_id, child1_id, child2a_id, child2b_id) = (
            id_of("OneChild"),
            id_of("TwoChildren"),
            id_of("Child1"),
            id_of("Child2a"),
            id_of("Child2b"),
        );
        let no_id = id_of("NoChild");

        for (child, parent) in [
            (child1_id, one_id),
            (child2a_id, two_id),
            (child2b_id, two_id),
        ] {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_parent",
                    json!({"entity_id": child, "parent_id": parent}),
                )
                .unwrap();
            drop(mcp);
            app.update();
            app.update();
        }

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_with_exactly_one_child", json!({}))
            .unwrap();
        assert!(out.is_ok());
        let ents = out.content["entities"].as_array().unwrap();
        let ids: Vec<u64> = ents.iter().map(|e| e["id"].as_u64().unwrap()).collect();
        assert!(ids.contains(&one_id), "OneChild (has 1 child) included");
        assert!(
            !ids.contains(&two_id),
            "TwoChildren (has 2 children) excluded"
        );
        assert!(!ids.contains(&no_id), "NoChild (has 0 children) excluded");
    }

