    #[test]
    fn mcp_set_selection_parent_parents_all_selected_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "Root"})).unwrap();
            m.execute("spawn_entity", json!({"name": "A"})).unwrap();
            m.execute("spawn_entity", json!({"name": "B"})).unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (root_id, a_id, b_id) = (id_of("Root"), id_of("A"), id_of("B"));

        // Select A and B
        for id in [a_id, b_id] {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": id}))
                .unwrap();
        }

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute("set_selection_parent", json!({"parent_id": root_id}))
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["parented_count"].as_u64().unwrap(), 2);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let parent_of = |id: u64| {
            ents.iter()
                .find(|e| e["id"].as_u64() == Some(id))
                .and_then(|e| e["parent_id"].as_u64())
        };
        assert_eq!(parent_of(a_id), Some(root_id), "A parent = Root");
        assert_eq!(parent_of(b_id), Some(root_id), "B parent = Root");
        assert!(parent_of(root_id).is_none(), "Root has no parent");
    }

    #[test]
    fn mcp_unparent_selection_removes_parent_from_selected_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "Root"})).unwrap();
            m.execute("spawn_entity", json!({"name": "A"})).unwrap();
            m.execute("spawn_entity", json!({"name": "B"})).unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (root_id, a_id, b_id) = (id_of("Root"), id_of("A"), id_of("B"));

        // Parent A and B to Root first
        for child in [a_id, b_id] {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_parent",
                    json!({"entity_id": child, "parent_id": root_id}),
                )
                .unwrap();
            drop(mcp);
            app.update();
            app.update();
        }

        // Select A only, then unparent
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": a_id}))
                .unwrap();
        }
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute("unparent_selection", json!({}))
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["unparented_count"].as_u64().unwrap(), 1);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let parent_of = |id: u64| {
            ents.iter()
                .find(|e| e["id"].as_u64() == Some(id))
                .and_then(|e| e["parent_id"].as_u64())
        };
        assert!(parent_of(a_id).is_none(), "A unparented");
        assert_eq!(parent_of(b_id), Some(root_id), "B still has Root parent");
    }

    #[test]
    fn mcp_get_entities_sorted_by_scale_returns_ascending_by_max_component() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({
                        "entities": [
                            {"name": "Big",    "position": [0.0, 0.0, 0.0]},
                            {"name": "Medium", "position": [1.0, 0.0, 0.0]},
                            {"name": "Small",  "position": [2.0, 0.0, 0.0]}
                        ]
                    }),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (big_id, med_id, small_id) = (id_of("Big"), id_of("Medium"), id_of("Small"));

        for (id, s) in [(big_id, 5.0f64), (med_id, 2.0), (small_id, 1.0)] {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_scale",
                    json!({"entity_id": id, "sx": s, "sy": s, "sz": s}),
                )
                .unwrap();
            drop(mcp);
            app.update();
            app.update();
        }

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_sorted_by_scale", json!({}))
            .unwrap();
        assert!(out.is_ok());
        let ents = out.content["entities"].as_array().unwrap();
        // Only entities with scale are returned; ascending by max component
        for i in 0..ents.len().saturating_sub(1) {
            let a = ents[i]["max_scale"].as_f64().unwrap();
            let b = ents[i + 1]["max_scale"].as_f64().unwrap();
            assert!(a <= b, "ascending: {} <= {}", a, b);
        }
        assert_eq!(ents.first().and_then(|e| e["name"].as_str()), Some("Small"));
        assert_eq!(ents.last().and_then(|e| e["name"].as_str()), Some("Big"));
    }

