    #[test]
    fn mcp_get_entities_with_no_children_returns_leaf_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "Root"})).unwrap();
            m.execute("spawn_entity", json!({"name": "Child"})).unwrap();
            m.execute("spawn_entity", json!({"name": "Leaf"})).unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let id_of = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (root_id, child_id, leaf_id) = (id_of("Root"), id_of("Child"), id_of("Leaf"));

        // Root → Child, Child → Leaf (Leaf has no children)
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_parent",
                    json!({"entity_id": child_id, "parent_id": root_id}),
                )
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_parent",
                    json!({"entity_id": leaf_id, "parent_id": child_id}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_entities_with_no_children", json!({}))
            .unwrap();
        assert!(out.is_ok());
        let ents = out.content["entities"].as_array().unwrap();
        let ids: Vec<u64> = ents.iter().map(|e| e["id"].as_u64().unwrap()).collect();
        assert!(ids.contains(&leaf_id), "Leaf is childless");
        assert!(!ids.contains(&root_id), "Root has children");
        assert!(!ids.contains(&child_id), "Child has children");
    }

    #[test]
    fn mcp_move_selection_by_moves_all_selected_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({
                        "entities": [
                            {"name": "A", "position": [0.0, 0.0, 0.0]},
                            {"name": "B", "position": [10.0, 0.0, 0.0]},
                            {"name": "C", "position": [20.0, 0.0, 0.0]}
                        ]
                    }),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let find_id = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (id_a, id_b, id_c) = (find_id("A"), find_id("B"), find_id("C"));

        // Select A and B
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": id_a}))
                .unwrap();
        }
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": id_b}))
                .unwrap();
        }

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute(
                    "move_selection_by",
                    json!({"dx": 5.0, "dy": 0.0, "dz": 0.0}),
                )
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["moved_count"].as_u64().unwrap(), 2);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let pos_of = |id: u64| {
            ents.iter()
                .find(|e| e["id"].as_u64() == Some(id))
                .and_then(|e| e["position"].as_array())
                .map(|p| p[0].as_f64().unwrap())
                .unwrap_or(f64::NAN)
        };
        assert!(
            (pos_of(id_a) - 5.0).abs() < 0.01,
            "A moved to 5, got {}",
            pos_of(id_a)
        );
        assert!(
            (pos_of(id_b) - 15.0).abs() < 0.01,
            "B moved to 15, got {}",
            pos_of(id_b)
        );
        assert!(
            (pos_of(id_c) - 20.0).abs() < 0.01,
            "C unchanged, got {}",
            pos_of(id_c)
        );
    }

    #[test]
    fn mcp_scale_selection_by_scales_all_selected_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({
                        "entities": [
                            {"name": "A", "position": [0.0, 0.0, 0.0]},
                            {"name": "B", "position": [1.0, 0.0, 0.0]}
                        ]
                    }),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let all = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone()
        };
        let find_id = |name: &str| {
            all.iter()
                .find(|e| e["name"].as_str() == Some(name))
                .unwrap()["id"]
                .as_u64()
                .unwrap()
        };
        let (id_a, id_b) = (find_id("A"), find_id("B"));

        // Set initial scale for A
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "set_scale",
                    json!({"entity_id": id_a, "sx": 2.0, "sy": 2.0, "sz": 2.0}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        // Select A only
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": id_a}))
                .unwrap();
        }

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute(
                    "scale_selection_by",
                    json!({"sx": 3.0, "sy": 1.0, "sz": 1.0}),
                )
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["scaled_count"].as_u64().unwrap(), 1);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let scale_x_of = |id: u64| {
            ents.iter()
                .find(|e| e["id"].as_u64() == Some(id))
                .and_then(|e| e["scale"].as_array())
                .map(|s| s[0].as_f64().unwrap())
                .unwrap_or(f64::NAN)
        };
        // A started at (2,2,2), multiplied by (3,1,1) → (6,2,2)
        assert!(
            (scale_x_of(id_a) - 6.0).abs() < 0.01,
            "A scale_x = 6, got {}",
            scale_x_of(id_a)
        );
        // B untouched — batch_spawn gives default scale [1,1,1]
        assert!(
            (scale_x_of(id_b) - 1.0).abs() < 0.01,
            "B scale_x unchanged, got {}",
            scale_x_of(id_b)
        );
    }

