    #[test]
    fn mcp_batch_tag_entities_adds_tag_to_multiple_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "A"})).unwrap();
            m.execute("spawn_entity", json!({"name": "B"})).unwrap();
            m.execute("spawn_entity", json!({"name": "C"})).unwrap();
        }
        app.update();
        app.update();

        let ids: Vec<u64> = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .iter()
                .map(|e| e["id"].as_u64().unwrap())
                .collect()
        };
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute(
                    "batch_tag_entities",
                    json!({"entity_ids": [ids[0], ids[1]], "tag": "group"}),
                )
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["tagged_count"].as_u64().unwrap(), 2);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        let tagged: Vec<u64> = ents
            .iter()
            .filter(|e| {
                e["tags"]
                    .as_array()
                    .map(|t| t.iter().any(|v| v.as_str() == Some("group")))
                    .unwrap_or(false)
            })
            .map(|e| e["id"].as_u64().unwrap())
            .collect();
        assert_eq!(tagged.len(), 2, "A and B tagged with 'group'");
    }

    #[test]
    fn mcp_batch_untag_entities_removes_tag_from_multiple_entities() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "X"})).unwrap();
            m.execute("spawn_entity", json!({"name": "Y"})).unwrap();
        }
        app.update();
        app.update();

        let ids: Vec<u64> = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .iter()
                .map(|e| e["id"].as_u64().unwrap())
                .collect()
        };
        for &eid in &ids {
            {
                let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
                mcp.0
                    .lock()
                    .unwrap()
                    .execute("tag_entity", json!({"entity_id": eid, "tag": "remove_me"}))
                    .unwrap();
            }
            app.update();
            app.update();
        }
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let out = mcp
                .0
                .lock()
                .unwrap()
                .execute(
                    "batch_untag_entities",
                    json!({"entity_ids": [ids[0], ids[1]], "tag": "remove_me"}),
                )
                .unwrap();
            assert!(out.is_ok());
            assert_eq!(out.content["untagged_count"].as_u64().unwrap(), 2);
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let ents = mcp
            .0
            .lock()
            .unwrap()
            .execute("list_entities", json!({}))
            .unwrap()
            .content["entities"]
            .as_array()
            .unwrap()
            .clone();
        for e in &ents {
            let tags = e["tags"].as_array().unwrap();
            assert!(
                !tags.iter().any(|t| t.as_str() == Some("remove_me")),
                "tag removed from all entities"
            );
        }
    }

    #[test]
    fn mcp_get_entities_with_tag_any_returns_entities_with_any_matching_tag() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let m = mcp.0.lock().unwrap();
            m.execute("spawn_entity", json!({"name": "HasAlpha"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "HasBeta"}))
                .unwrap();
            m.execute("spawn_entity", json!({"name": "HasNeither"}))
                .unwrap();
        }
        app.update();
        app.update();

        let (alpha_id, beta_id) = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let ents = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let a = ents
                .iter()
                .find(|e| e["name"].as_str() == Some("HasAlpha"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let b = ents
                .iter()
                .find(|e| e["name"].as_str() == Some("HasBeta"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            (a, b)
        };
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": alpha_id, "tag": "alpha"}))
                .unwrap();
        }
        app.update();
        app.update();
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("tag_entity", json!({"entity_id": beta_id, "tag": "beta"}))
                .unwrap();
        }
        app.update();
        app.update();

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let out = mcp
            .0
            .lock()
            .unwrap()
            .execute(
                "get_entities_with_tag_any",
                json!({"tags": ["alpha", "beta"]}),
            )
            .unwrap();
        assert!(out.is_ok());
        let ids: Vec<u64> = out.content["entities"]
            .as_array()
            .unwrap()
            .iter()
            .map(|e| e["id"].as_u64().unwrap())
            .collect();
        assert_eq!(ids.len(), 2, "HasAlpha and HasBeta both match");
        assert!(ids.contains(&alpha_id));
        assert!(ids.contains(&beta_id));
    }

