    #[test]
    fn mcp_invert_selection_swaps_selected_and_unselected() {
        let mut app = new_app();
        app.add_plugins(McpPlugin);
        app.add_plugins(EditorPlugin);

        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute(
                    "batch_spawn",
                    json!({"entities": [
                        {"name": "InvSelA"},
                        {"name": "InvSelB"},
                        {"name": "InvSelC"}
                    ]}),
                )
                .unwrap();
        }
        app.update();
        app.update();

        let (id_a, id_b, id_c) = {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            let ents = mcp
                .0
                .lock()
                .unwrap()
                .execute("list_entities", json!({}))
                .unwrap()
                .content["entities"]
                .as_array()
                .unwrap()
                .clone();
            let a = ents
                .iter()
                .find(|e| e["name"].as_str() == Some("InvSelA"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let b = ents
                .iter()
                .find(|e| e["name"].as_str() == Some("InvSelB"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            let c = ents
                .iter()
                .find(|e| e["name"].as_str() == Some("InvSelC"))
                .unwrap()["id"]
                .as_u64()
                .unwrap();
            (a, b, c)
        };
        // select only A
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("select_entity", json!({"entity_id": id_a}))
                .unwrap();
        }
        // invert selection → B and C selected, A deselected
        {
            let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
            mcp.0
                .lock()
                .unwrap()
                .execute("invert_selection", json!({}))
                .unwrap();
        }

        let mcp = app.world().resource::<bsengine_mcp::McpRegistryResource>();
        let sel = mcp
            .0
            .lock()
            .unwrap()
            .execute("get_selection", json!({}))
            .unwrap();
        let ids: Vec<u64> = sel.content["selected_ids"]
            .as_array()
            .unwrap()
            .iter()
            .map(|e| e.as_u64().unwrap())
            .collect();
        assert!(
            !ids.contains(&id_a),
            "A was selected before → not selected after invert"
        );
        assert!(
            ids.contains(&id_b),
            "B was not selected → selected after invert"
        );
        assert!(
            ids.contains(&id_c),
            "C was not selected → selected after invert"
        );
    }

